590			return nil, nil, nil, fmt.Errorf("convert-sha256 currently supports HTTP/HTTPS sources only; got %q", ep.Scheme)
591		}
592		authMethod, err := auth.Resolve(auth.Endpoint{
593			Username:      req.SourceAuth.Username,
594			Token:         req.SourceAuth.Token,
595			BearerToken:   req.SourceAuth.BearerToken,
596			SkipTLSVerify: req.SourceAuth.SkipTLSVerify,
597		}, ep)
598		if err != nil {
599			return nil, nil, nil, fmt.Errorf("resolve source auth: %w", err)
600		}
601		httpClient := &http.Client{Transport: gitproto.NewHTTPTransport(req.SourceAuth.SkipTLSVerify)}
602		conn := gitproto.NewHTTPConnWithClient(ep, "source", normalizeAuth(authMethod), httpClient)
603		conn.FollowInfoRefsRedirect = req.SourceFollowInfoRefsRedirect
604	
605		mode := string(req.ProtocolMode)
606		if mode == "" {
607			mode = string(gitsync.ProtocolAuto)
608		}
609	
610		refs, svc, err := gitproto.ListSourceRefs(ctx, conn, mode, planner.RefPrefixes(planCfg))
611		if err != nil {
612			_ = conn.Close()
613			return nil, nil, nil, fmt.Errorf("list source refs: %w", err)
614		}
615		return conn, svc, refs, nil
