850	func (t *translator) translate(sha1 plumbing.Hash) (plumbing.Hash, error) {
851		if newH, ok := t.mapping[sha1]; ok {
852			return newH, nil
853		}
854		if _, busy := t.inProgress[sha1]; busy {
855			// Real Git histories cannot form cycles via parent, tree, or
856			// tag-target edges (those are a DAG by construction), and
857			// SHA1 message-reference cycles are cryptographically
858			// infeasible (each commit's hash depends on its content,
859			// including any hash it embeds). A trip here would mean an
860			// unexpected graph shape; surface it instead of overflowing
861			// the stack.
862			return plumbing.ZeroHash, fmt.Errorf("translation cycle detected at %s", sha1)
863		}
864		t.inProgress[sha1] = struct{}{}
865		defer delete(t.inProgress, sha1)
866	
867		obj, err := t.src.EncodedObject(plumbing.AnyObject, sha1)
868		if err != nil {
869			return plumbing.ZeroHash, fmt.Errorf("lookup %s: %w", sha1, err)
870		}
871		switch obj.Type() { //nolint:exhaustive // OFSDelta/REFDelta/AnyObject/InvalidObject cannot reach a resolved storage.
